+            var customProperties = getOverlayPropertiesFunc(entityID, properties);
+            for (var key in customProperties) {
+                overlayProperties[key] = customProperties[key];
+            }
+        }
+        Entities.editEntity(entityOverlays[entityID], overlayProperties);
+    }
